INSERT INTO public.changelog (version, title, body, released_at) VALUES ('1.7.3', 'بازسازی ویرایشگر و بازگشت مداد', E'- بازگشت ابزار مداد با کنترل رنگ، ضخامت، پاک‌کن و پاک‌سازی\n- مداد فقط روی ناحیه متن اثر می‌گذارد (سرصفحه و منوبار دست‌نخورده)\n- اگر متنی انتخاب نشده باشد، دکمه‌های ویرایش (Bold/Italic/Align/…) روی کل سند اعمال می‌شوند؛ در صورت انتخاب، فقط روی بخش انتخاب‌شده\n- اصلاح تداخل‌های Tiptap و پایدارسازی نوار ابزار Word', now());